from microbit import *
import random

opciones = ['Pedra', 'Papel', 'Tesoira']

while True:
    xogador = None
    if button_a.is_pressed() and button_b.is_pressed():
        xogador = 2   # Tesoira
    elif button_a.is_pressed():
        xogador = 0   # Pedra
    elif button_b.is_pressed():
        xogador = 1   # Papel

    if xogador is not None:
        maquina = random.randint(0, 2)
        display.scroll(opciones[xogador])
        if xogador == maquina:
            display.scroll('Empate!')
        elif (xogador - maquina) % 3 == 1:
            display.scroll('GAÑAS!')
        else:
            display.scroll('Perdes...')
    sleep(200)

