from microbit import *

while True:
    luz  = display.read_light_level()  # 0-255
    temp = temperature()               # graos Celsius

    display.scroll('L:' + str(luz) + ' T:' + str(temp), delay=60)

    if luz < 50:
        display.show(Image.ASLEEP)     # Moi escuro
    elif temp > 28:
        display.show(Image.SURPRISED)  # Moita calor
    else:
        display.show(Image.HAPPY)
    sleep(1500)

