# Botóns xigantes con pins
from microbit import *

# Pins 0 e 1 como entradas (botóns)
# Conectar o pin 0 a GND para pulsar o botón GRANDE (ex: pinza ao pin 0, outra a GND/P0)
# Conectar o pin 1 a GND para pulsar o botón GRANDE (ex: pinza ao pin 1, outra a GND/P1)

while True:
    if pin0.is_touched(): # Detecta se o pin está conectado a GND (pulsado)
        display.show(Image.YES)
    elif pin1.is_touched():
        display.show(Image.NO)
    else:
        display.clear()
    sleep(50)
